// This file has been moved to src/.
import React, { useState, useEffect, useRef } from "react";
import { PRIORITIES, STATUSES } from "../utils/constants";

const EMPTY = { title: "", description: "", priority: "Medium", status: "Open" };

export default function FeatureModal({ feature, onSave, onClose }) {
  const [form, setForm] = useState(feature ? { ...feature } : { ...EMPTY });
  const [errors, setErrors] = useState({});
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(feature?.imageUrl || null);
  const [dragging, setDragging] = useState(false);
  const titleRef = useRef(null);
  const fileInputRef = useRef(null);

  const isEdit = Boolean(feature);

  useEffect(() => { titleRef.current?.focus(); }, []);

  useEffect(() => {
    const handler = (e) => { if (e.key === "Escape") onClose(); };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose]);

  function validate() {
    const errs = {};
    if (!form.title.trim()) errs.title = "Title is required.";
    else if (form.title.trim().length < 3) errs.title = "Title must be at least 3 characters.";
    if (!form.description.trim()) errs.description = "Description is required.";
    return errs;
  }

  function handleChange(e) {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
    if (errors[name]) setErrors((er) => ({ ...er, [name]: undefined }));
  }

  function handleSubmit(e) {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    onSave({ ...form, image: imageFile });
    onClose();
  }

  function applyImageFile(file) {
    if (!file || !file.type.startsWith("image/")) return;
    setImageFile(file);
    setImagePreview(URL.createObjectURL(file));
  }

  function handleFileInput(e) { applyImageFile(e.target.files[0]); }

  function handleDrop(e) {
    e.preventDefault();
    setDragging(false);
    applyImageFile(e.dataTransfer.files[0]);
  }

  function removeImage() {
    setImageFile(null);
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  }

  return (
    <div className="modal-backdrop" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal" role="dialog" aria-modal="true" aria-label={isEdit ? "Edit Feature" : "New Feature"}>

        <div className="modal-header">
          <h2 className="modal-title">{isEdit ? "Edit Request" : "New Request"}</h2>
          <button className="btn-icon" onClick={onClose} aria-label="Close">✕</button>
        </div>

        <form onSubmit={handleSubmit} noValidate>

          {/* Title */}
          <div className="field">
            <label htmlFor="title">Title</label>
            <input
              ref={titleRef}
              id="title" name="title" type="text"
              value={form.title} onChange={handleChange}
              placeholder="Short, descriptive title…"
              className={errors.title ? "input-error" : ""}
              autoComplete="off"
            />
            {errors.title && <span className="error-msg">{errors.title}</span>}
          </div>

          {/* Description */}
          <div className="field">
            <label htmlFor="description">Description</label>
            <textarea
              id="description" name="description"
              value={form.description} onChange={handleChange}
              placeholder="What should this feature do?"
              rows={4}
              className={errors.description ? "input-error" : ""}
            />
            {errors.description && <span className="error-msg">{errors.description}</span>}
          </div>

          {/* Priority + Status */}
          <div className="field-row">
            <div className="field">
              <label htmlFor="priority">Priority</label>
              <select id="priority" name="priority" value={form.priority} onChange={handleChange}>
                {PRIORITIES.map((p) => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
            <div className="field">
              <label htmlFor="status">Status</label>
              <select id="status" name="status" value={form.status} onChange={handleChange}>
                {STATUSES.map((s) => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          </div>

          {/* ── Image Upload ── */}
          <div className="field">
            <label>
              Image <span style={{ fontWeight: 400, color: "var(--text-3)", fontSize: 11, textTransform: "none", letterSpacing: 0 }}>(optional)</span>
            </label>

            {imagePreview ? (
              /* Preview state */
              <div style={{ position: "relative", display: "inline-block" }}>
                <img
                  src={imagePreview}
                  alt="preview"
                  style={{
                    display: "block", width: "100%", maxHeight: 180,
                    objectFit: "cover", borderRadius: "var(--radius)",
                    border: "1px solid var(--accent)",
                  }}
                />
                {/* Change button */}
                <label style={{
                  position: "absolute", bottom: 8, left: 8,
                  background: "var(--accent)", color: "#fff",
                  borderRadius: 6, padding: "4px 12px",
                  fontSize: 12, fontWeight: 600, cursor: "pointer",
                  fontFamily: "var(--font-mono)",
                }}>
                  📁 Change
                  <input
                    ref={fileInputRef} type="file" accept="image/*"
                    style={{ display: "none" }} onChange={handleFileInput}
                  />
                </label>
                {/* Remove button */}
                <button
                  type="button" onClick={removeImage}
                  style={{
                    position: "absolute", top: 8, right: 8,
                    background: "rgba(0,0,0,0.6)", color: "#fff",
                    border: "none", borderRadius: "50%",
                    width: 28, height: 28, fontSize: 14,
                    cursor: "pointer", display: "flex",
                    alignItems: "center", justifyContent: "center",
                  }}
                  title="Remove image"
                >✕</button>
              </div>
            ) : (
              /* Drop-zone state */
              <div
                className={`upload-zone${dragging ? " dragging" : ""}`}
                onDragOver={(e) => { e.preventDefault(); setDragging(true); }}
                onDragLeave={() => setDragging(false)}
                onDrop={handleDrop}
                onClick={() => fileInputRef.current?.click()}
              >
                <div className="upload-zone-icon">🖼️</div>
                <div className="upload-zone-text">
                  Drag & drop an image, or <span>browse</span>
                </div>
                <div className="upload-zone-hint">PNG, JPG, GIF, WEBP</div>
                <input
                  ref={fileInputRef} type="file" accept="image/*"
                  style={{ display: "none" }} onChange={handleFileInput}
                />
              </div>
            )}
          </div>
          {/* ────────────────────────────────────────────────── */}

          <div className="modal-footer">
            <button type="button" className="btn btn-ghost" onClick={onClose}>Cancel</button>
            <button type="submit" className="btn btn-primary">
              {isEdit ? "Save Changes" : "Add Request"}
            </button>
          </div>

        </form>
      </div>
    </div>
  );
}
